import React, { useState } from 'react';
import '../styles/components/Experience.css';

function Experience() {
  const [activeCategory, setActiveCategory] = useState('All');
  const [expandedItems, setExpandedItems] = useState([]);

  const experiences = [
    {
      type: 'Organisasi',
      title: 'Ketua Divisi IT',
      organization: 'Himpunan Mahasiswa',
      period: '2024 - Present',
      description: 'Memimpin tim IT dalam pengembangan sistem dan infrastruktur teknologi organisasi. Bertanggung jawab atas pengelolaan website, sistem informasi, dan mendukung seluruh kegiatan organisasi dengan solusi teknologi.'
    },
    {
      type: 'Kepanitiaan',
      title: 'Koordinator Acara',
      organization: 'Seminar Nasional Tech 2024',
      period: '2024',
      description: 'Mengkoordinir 50+ panitia dalam pelaksanaan seminar dengan 500+ peserta. Mengelola timeline acara, koordinasi dengan sponsor, dan memastikan kelancaran teknis acara.'
    },
    {
      type: 'Organisasi',
      title: 'Staff Divisi Media',
      organization: 'BEM Fakultas',
      period: '2023 - 2024',
      description: 'Mengelola konten media sosial dan dokumentasi kegiatan organisasi. Membuat desain grafis untuk publikasi dan meningkatkan engagement media sosial hingga 200%.'
    },
    {
      type: 'Kepanitiaan',
      title: 'Sie Publikasi',
      organization: 'Workshop Programming',
      period: '2023',
      description: 'Bertanggung jawab dalam promosi dan publikasi event workshop. Mengelola strategi marketing digital dan mencapai target peserta 150 orang.'
    },
    {
      type: 'Organisasi',
      title: 'Anggota Tim Web Development',
      organization: 'Unit Kegiatan Mahasiswa',
      period: '2023 - 2024',
      description: 'Mengembangkan dan maintain website organisasi menggunakan React dan Node.js. Implementasi fitur manajemen anggota dan galeri kegiatan.'
    },
    {
      type: 'Kepanitiaan',
      title: 'Sie Acara',
      organization: 'Festival Teknologi',
      period: '2023',
      description: 'Merencanakan dan mengeksekusi rangkaian acara festival dengan 30+ booth exhibitor. Koordinasi dengan vendor dan memastikan semua acara berjalan sesuai jadwal.'
    }
  ];

  const filteredExperiences = activeCategory === 'All' 
    ? experiences 
    : experiences.filter(exp => exp.type === activeCategory);

  const toggleExpand = (index) => {
    if (expandedItems.includes(index)) {
      setExpandedItems(expandedItems.filter(i => i !== index));
    } else {
      setExpandedItems([...expandedItems, index]);
    }
  };

  return (
    <section id="experience" className="experience">
      <div className="container">
        <h2 className="section-title">Experience</h2>
        
        <div className="experience-categories">
          <button 
            className={`category-btn ${activeCategory === 'All' ? 'active' : ''}`}
            onClick={() => setActiveCategory('All')}
          >
            All
          </button>
          <button 
            className={`category-btn ${activeCategory === 'Organisasi' ? 'active' : ''}`}
            onClick={() => setActiveCategory('Organisasi')}
          >
            Organisasi
          </button>
          <button 
            className={`category-btn ${activeCategory === 'Kepanitiaan' ? 'active' : ''}`}
            onClick={() => setActiveCategory('Kepanitiaan')}
          >
            Kepanitiaan
          </button>
        </div>

        <div className="experience-grid">
          {filteredExperiences.map((exp, index) => (
            <div 
              key={index} 
              className={`experience-item ${expandedItems.includes(index) ? 'expanded' : ''}`}
            >
              <div className="experience-header">
                <div>
                  <h3>{exp.title}</h3>
                  <h4>{exp.organization}</h4>
                </div>
                <span className="experience-type">{exp.type}</span>
              </div>
              <span className="period">
                <span>📅</span>
                {exp.period}
              </span>
              <p>{exp.description}</p>
              {exp.description.length > 150 && (
                <span 
                  className="read-more" 
                  onClick={() => toggleExpand(index)}
                >
                  {expandedItems.includes(index) ? 'Show less' : 'Read more'} →
                </span>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
